154	                || regs->regs[28] >= vma.begin && regs->regs[28] < vma.end
155	                || regs->regs[29] >= vma.begin && regs->regs[29] < vma.end
156	                || regs->regs[30] >= vma.begin && regs->regs[30] < vma.end
