166	void Opencore::WriteCoreFpRegs(int tid, FILE* fp) {
167	    // NT_FPREGSET
168	    Elf64_Nhdr elf_nhdr;
169	    elf_nhdr.n_namesz = NOTE_CORE_NAME_SZ;
170	    elf_nhdr.n_descsz = sizeof(Elf64_fpregset);
